1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const HIGH_DAMAGE_ENCHANTMENT_THRESHOLD = 8;
12	const HIGH_ENCHANTMENT_DAMAGE_RATE = 0.5;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
33	type Customer = { yearsWithMHPCO: number };
34	type Damage = { itemType: string; amount: number };
35	type Incident = { cause: string; damages: Damage[] };
36	type QuoteStep = { op: "quote"; items: Item[] };
37	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
38	type Step = QuoteStep | ClaimStep;
39	type Scenario = { customer: Customer; steps: Step[] };
40	type QuoteResult = { premium: number };
41	type ClaimResult = { payout: number; remainingCap: number };
42	type StepResult = QuoteResult | ClaimResult;
43	
44	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const BLOCK_SIZE = 3;
48	const BLOCK_BASE_PREMIUM = 60;
49	
50	const sumBasePremiums = (items: Item[]): number =>
51	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
52	
53	const componentGroupSubtotalOf = (group: Item[]): number =>
54	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
55	
56	const groupByType = (items: Item[]): Item[][] => {
57	  const groups = new Map<string, Item[]>();
58	  for (const item of items) {
59	    const group = groups.get(item.type);
60	    if (group) {
61	      group.push(item);
62	    } else {
63	      groups.set(item.type, [item]);
64	    }
65	  }
66	  return [...groups.values()];
67	};
68	
69	const componentSubtotalOf = (components: Item[]): number =>
70	  groupByType(components).reduce(
71	    (sum, group) => sum + componentGroupSubtotalOf(group),
72	    0,
73	  );
74	
75	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
76	
77	const policyBaseOf = (items: Item[]): number => {
78	  const components = items.filter(isComponent);
79	  const standaloneItems = items.filter((item) => !isComponent(item));
80	  return sumBasePremiums(standaloneItems) + componentSubtotalOf(components);
81	};
82	
83	const firstInsuranceSurchargeOf = (policyBase: number): number =>
84	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
85	
86	const cursedSurchargeOf = (item: Item): number =>
87	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
88	
89	const highEnchantmentSurchargeOf = (item: Item): number =>
90	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
91	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
92	    : 0;
93	
94	const itemSurchargeOf = (item: Item): number =>
95	  cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item);
96	
97	const itemSurchargesOf = (items: Item[]): number =>
98	  items.reduce((sum, item) => sum + itemSurchargeOf(item), 0);
99	
100	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
101	
102	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
103	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
104	
105	const followUpDiscountOf = (policyBase: number, isFollowUp: boolean): number =>
106	  isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
107	
108	const policySurchargesOf = (policyBase: number): number =>
109	  firstInsuranceSurchargeOf(policyBase);
110	
111	const policyDiscountsOf = (
112	  policyBase: number,
113	  customer: Customer,
114	  isFollowUp: boolean,
115	): number =>
116	  loyaltyDiscountOf(policyBase, customer) + followUpDiscountOf(policyBase, isFollowUp);
117	
118	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
119	  const policyBase = policyBaseOf(items);
120	  const surcharges = itemSurchargesOf(items) + policySurchargesOf(policyBase);
121	  const discounts = policyDiscountsOf(policyBase, customer, isFollowUp);
122	  const rawPremium = policyBase + surcharges - discounts + PROCESSING_FEE;
123	  return roundUpInMHPCOFavor(rawPremium);
124	};
125	
126	const isFollowUpContract = (stepIndex: number): boolean => stepIndex > 0;
127	
128	const insuranceSumOf = (items: Item[]): number =>
129	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
130	
131	const reimbursableAmountOf = (damage: Damage, insuredItem: Item): number =>
132	  (insuredItem.enchantment ?? 0) >= HIGH_DAMAGE_ENCHANTMENT_THRESHOLD
133	    ? damage.amount * HIGH_ENCHANTMENT_DAMAGE_RATE
134	    : damage.amount;
135	
136	const damagePayoutOf = (damage: Damage, insuredItem: Item): number =>
137	  reimbursableAmountOf(damage, insuredItem) - DEDUCTIBLE;
138	
139	const findInsuredItem = (itemType: string, items: Item[]): Item =>
140	  items.find((item) => item.type === itemType) as Item;
141	
142	const incidentPayoutOf = (incident: Incident, policyItems: Item[]): number =>
143	  incident.damages.reduce(
144	    (sum, damage) => sum + damagePayoutOf(damage, findInsuredItem(damage.itemType, policyItems)),
145	    0,
146	  );
147	
148	const policyCapOf = (originatingQuote: QuoteStep): number =>
149	  insuranceSumOf(originatingQuote.items) * CAP_MULTIPLIER;
150	
151	const originatingQuoteOf = (claimStep: ClaimStep, scenario: Scenario): QuoteStep =>
152	  scenario.steps[claimStep.policy] as QuoteStep;
153	
154	const processClaim = (claimStep: ClaimStep, scenario: Scenario): ClaimResult => {
155	  const originatingQuote = originatingQuoteOf(claimStep, scenario);
156	  const payout = incidentPayoutOf(claimStep.incident, originatingQuote.items);
157	  const cap = policyCapOf(originatingQuote);
158	  return { payout, remainingCap: cap - payout };
159	};
160	
161	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
162	  const results: StepResult[] = scenario.steps.map((step, index) => {
163	    if (step.op === "quote") {
164	      return {
165	        premium: quotePremium(step.items, scenario.customer, isFollowUpContract(index)),
166	      };
167	    }
168	    return processClaim(step, scenario);
169	  });
170	  return { results };
171	};
